import { Injectable } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { Observable } from 'rxjs';
import { environment } from '../../environments/environment';
import {
  AdminSetting,
  Course,
  Enrollment,
  GradebookRow,
  Lesson,
  Module,
  Progress,
  Question,
  Quiz,
  QuizAttemptResult,
  User,
} from './models';

/**
 * LearnLoop API client. Typed against models.ts and the surface contract.
 * The mockup pages render local signal mock data; the service_agent stage
 * wires these methods into the page components via ngOnInit().
 */
@Injectable({ providedIn: 'root' })
export class ApiService {
  private readonly base = environment.apiUrl;

  constructor(private http: HttpClient) {}

  // ---- Users ----
  me(): Observable<User> {
    return this.http.get<User>(`${this.base}/users/me`);
  }

  // ---- Courses (public reads, instructor writes) ----
  listCourses(): Observable<Course[]> {
    return this.http.get<Course[]>(`${this.base}/courses`);
  }
  getCourse(id: string): Observable<Course> {
    return this.http.get<Course>(`${this.base}/courses/${id}`);
  }
  createCourse(body: Partial<Course>): Observable<Course> {
    return this.http.post<Course>(`${this.base}/courses`, body);
  }
  updateCourse(id: string, body: Partial<Course>): Observable<Course> {
    return this.http.patch<Course>(`${this.base}/courses/${id}`, body);
  }
  deleteCourse(id: string): Observable<void> {
    return this.http.delete<void>(`${this.base}/courses/${id}`);
  }

  // ---- Modules (instructor) ----
  createModule(courseId: string, body: Partial<Module>): Observable<Module> {
    return this.http.post<Module>(`${this.base}/courses/${courseId}/modules`, body);
  }
  updateModule(id: string, body: Partial<Module>): Observable<Module> {
    return this.http.patch<Module>(`${this.base}/modules/${id}`, body);
  }
  deleteModule(id: string): Observable<void> {
    return this.http.delete<void>(`${this.base}/modules/${id}`);
  }

  // ---- Lessons ----
  getLesson(id: string): Observable<Lesson> {
    return this.http.get<Lesson>(`${this.base}/lessons/${id}`);
  }
  viewLesson(id: string): Observable<Progress> {
    return this.http.post<Progress>(`${this.base}/lessons/${id}/view`, {});
  }
  createLesson(moduleId: string, body: Partial<Lesson>): Observable<Lesson> {
    return this.http.post<Lesson>(`${this.base}/modules/${moduleId}/lessons`, body);
  }
  updateLesson(id: string, body: Partial<Lesson>): Observable<Lesson> {
    return this.http.patch<Lesson>(`${this.base}/lessons/${id}`, body);
  }
  deleteLesson(id: string): Observable<void> {
    return this.http.delete<void>(`${this.base}/lessons/${id}`);
  }

  // ---- Learning: enroll, my-courses, progress ----
  enroll(courseId: string): Observable<Enrollment> {
    return this.http.post<Enrollment>(`${this.base}/courses/${courseId}/enroll`, {});
  }
  myCourses(): Observable<Enrollment[]> {
    return this.http.get<Enrollment[]>(`${this.base}/enrollments/mine`);
  }
  getProgress(courseId: string): Observable<Progress> {
    return this.http.get<Progress>(`${this.base}/courses/${courseId}/progress`);
  }

  // ---- Quizzes ----
  getQuiz(id: string): Observable<Quiz> {
    return this.http.get<Quiz>(`${this.base}/quizzes/${id}`);
  }
  submitAttempt(id: string, answers: number[]): Observable<QuizAttemptResult> {
    return this.http.post<QuizAttemptResult>(`${this.base}/quizzes/${id}/attempt`, { answers });
  }
  createQuiz(moduleId: string, body: Partial<Quiz>): Observable<Quiz> {
    return this.http.post<Quiz>(`${this.base}/modules/${moduleId}/quizzes`, body);
  }
  updateQuiz(id: string, body: Partial<Quiz>): Observable<Quiz> {
    return this.http.patch<Quiz>(`${this.base}/quizzes/${id}`, body);
  }
  deleteQuiz(id: string): Observable<void> {
    return this.http.delete<void>(`${this.base}/quizzes/${id}`);
  }

  // ---- Questions (instructor) ----
  createQuestion(quizId: string, body: Partial<Question>): Observable<Question> {
    return this.http.post<Question>(`${this.base}/quizzes/${quizId}/questions`, body);
  }
  updateQuestion(id: string, body: Partial<Question>): Observable<Question> {
    return this.http.patch<Question>(`${this.base}/questions/${id}`, body);
  }
  deleteQuestion(id: string): Observable<void> {
    return this.http.delete<void>(`${this.base}/questions/${id}`);
  }

  // ---- Gradebook (instructor) ----
  getGradebook(courseId: string): Observable<GradebookRow[]> {
    return this.http.get<GradebookRow[]>(`${this.base}/courses/${courseId}/gradebook`);
  }

  // ---- Admin settings ----
  getSettings(): Observable<AdminSetting[]> {
    return this.http.get<AdminSetting[]>(`${this.base}/admin/settings`);
  }
  updateSettings(payload: Record<string, string>): Observable<AdminSetting[]> {
    return this.http.patch<AdminSetting[]>(`${this.base}/admin/settings`, payload);
  }
}
